import { createContext, useContext } from 'react';
import type { OverlayHub } from '@arvo/core';

export const OverlayContext = createContext<OverlayHub | null>(null);

export function useOverlayContext(): OverlayHub {
  const hub = useContext(OverlayContext);
  if (!hub) {
    throw new Error('useOverlay must be used inside <OverlayProvider>');
  }
  return hub;
}
